updated = 0
INTROS.each do |id, text|
  s = Season.find_by(id: id)
  unless s
    warn "  ! Season #{id} not found — skipped"
    next
  end
  s.update!(intro: text.strip)
  puts "  ✓ #{s.series&.name} Season #{s.number} — #{s.intro.length} chars"
  updated += 1
end
puts ""
puts "Updated #{updated} / #{INTROS.size} seasons"
